def planarity_test(graph):
    """
    Grafın düzlemsel olup olmadığını test etmek için temel kontroller.

    Args:
        graph: Bir sözlük olarak temsil edilen bir graf.
               Anahtarlar düğümlerdir ve değerler komşuların listeleridir.

    Returns:
        True: Grafik, bu temel kontrollere göre düzlemsel ise.
        False: Grafik, bu temel kontrollere göre düzlemsel değilse.
    """

    num_vertices = len(graph)
    num_edges = sum(len(neighbors) for neighbors in graph.values()) // 2  # Çift sayıldığı için 2'ye bölün

    # Düzlemsel grafikler için Euler formülünü uygulayın (temel versiyon):
    # e <= 3v - 6  (v >= 3 için)
    if num_vertices >= 3 and num_edges > 3 * num_vertices - 6:
        return False

    # Çoklu grafikleri ve self döngüleri kaldırın.  Düzlemlilik testi için sade grafikleri ele almak en iyisidir.
    for vertex in graph:
        # Self döngüleri kontrol edin.
        if vertex in graph[vertex]:
            return False

        # Çoklu grafikleri kontrol edin (temel kontrol için sadece bir fikir verin).
        neighbors = graph[vertex]
        if len(neighbors) != len(set(neighbors)):
            return False # Birden çok kenar var gibi görünüyor.  Kesin tespit için tam olarak emin olamazsınız.

    # K5 ve K3,3 alt grafiklerinin varlığı için temel kontrol.
    # Tam olarak tespit etmek zordur, ancak rastgele düğüm kümelerini kontrol etmek kötü durumları yakalayabilir.
    import itertools

    def is_complete_graph(nodes, graph):
        """Verilen düğüm kümesinin grafikteki tam bir grafik oluşturup oluşturmadığını kontrol edin."""
        for u, v in itertools.combinations(nodes, 2):
            if v not in graph.get(u, []) and u not in graph.get(v, []):
                return False
        return True

    def is_complete_bipartite_graph(set1, set2, graph):
         """Verilen iki düğüm kümesinin grafikte tam bir iki parçalı grafik oluşturup oluşturmadığını kontrol edin."""
         for u in set1:
             for v in set2:
                 if v not in graph.get(u, []) and u not in graph.get(v, []):
                     return False
         return True

    # K5 için temel kontrol
    if num_vertices >= 5:
        for nodes in itertools.combinations(graph.keys(), 5):
            subgraph = {node: [neighbor for neighbor in graph[node] if neighbor in nodes] for node in nodes}
            if is_complete_graph(nodes, subgraph):
                return False

    # K3,3 için temel kontrol
    if num_vertices >= 6:
        for set1 in itertools.combinations(graph.keys(), 3):
            remaining_nodes = set(graph.keys()) - set(set1)
            for set2 in itertools.combinations(remaining_nodes, 3):

                subgraph = {node: [neighbor for neighbor in graph[node] if neighbor in set(set1) | set(set2)] for node in set(set1) | set(set2)}

                if is_complete_bipartite_graph(set1, set2, subgraph):
                   return False


    return True
